-- Курс 71: Менеджер по продажам B2B на удалёнке. 8 модулей, 48 уроков.
INSERT INTO t_p78828167_tutor_platform_1.course_curricula
  (course_id, course_title, subject, grade_band, total_lessons, total_modules, estimated_hours,
   program_description, learning_outcomes, target_audience, prerequisites, methodology, final_project,
   certificate_available, generated_by, version, is_fallback, ai_error, age_rating, disclaimers)
VALUES (
  71,
  'Менеджер по продажам B2B на удалёнке: от лида до сделки и плана',
  'sales', 'adult', 48, 8, 32,
  'Профессиональный курс по B2B-продажам — самой массовой удалённой профессии на рынке труда (около 17% всех удалённых вакансий приходится на менеджеров по продажам и работе с клиентами). От нуля до системного специалиста: воронка и этапы сделки, холодные звонки и письма, квалификация лидов, выявление потребностей по технике СПИН, презентация ценности, работа с возражениями, переговоры и закрытие, ведение CRM, специфика длинных B2B-сделок. Курс построен на реальных диалогах, скриптах и чек-листах.',
  '["Понимать воронку и этапы B2B-продаж","Делать результативные холодные звонки и письма","Квалифицировать лиды и не тратить время впустую","Выявлять потребности клиента по технике СПИН","Презентовать ценность, а не характеристики","Отрабатывать возражения и вести торг","Доводить сделки до закрытия","Вести CRM и планировать личные показатели"]'::jsonb,
  'Взрослые от 18 лет: новички без опыта продаж, начинающие менеджеры, фрилансеры и эксперты, которым нужно продавать свои услуги, сотрудники, желающие перейти на удалёнку с хорошим доходом.',
  '["Грамотная устная и письменная речь","Готовность общаться с людьми","Базовые навыки работы за компьютером"]'::jsonb,
  'Методика «навык за уроком»: каждый блок даёт конкретный приём, который сразу отрабатывается на разборе реального диалога и закрепляется скриптом или чек-листом. Чередование теории, практики на кейсах и звонках, контрольных тестов и финального проекта — проведение сделки от первого контакта до закрытия. Дополнительные материалы: скрипты звонков, шаблоны писем, банк ответов на возражения, чек-листы этапов сделки, шаблон личного плана продаж.',
  'Финальный проект: провести учебную B2B-сделку целиком — подготовить базу и скрипт, сделать холодный контакт, квалифицировать клиента, выявить потребности по СПИН, презентовать решение, отработать 3 возражения и закрыть сделку, зафиксировав всё в CRM. Результат — записанный кейс и заполнённая карточка сделки для портфолио.',
  TRUE, 'manual_expert', 1, FALSE, NULL, '18+',
  '["Материалы курса носят образовательный характер и описывают этичные техники продаж. Соблюдайте закон о рекламе и о защите прав потребителей, а также правила обработки персональных данных клиентов.","Курс предназначен для лиц старше 18 лет. Соблюдайте налоговое и трудовое законодательство РФ.","При прохождении курса соблюдается 152-ФЗ «О персональных данных»."]'::jsonb
);

